export interface LearnStep {
  step: number;
  title_en: string;
  title_ar: string;
  explanation_en: string;
  explanation_ar: string;
}

export interface LearnMethod {
  steps: LearnStep[];
  hint_en: string;
  hint_ar: string;
  result_en: string;
  result_ar: string;
}

export interface PracticeMeta {
  fun_fact_tag: string;
}

export interface LightPracticeProblem {
  id: string;
  grade: number;
  bank: 'common';
  category: 'Addition' | 'Subtraction' | 'Multiplication' | 'Division';
  level: 'Easy' | 'Medium' | 'Hard';
  question_en: string;
  question_ar: string;
  answer: number;
  learn_ref: string;
}

export interface FullPracticeProblem {
  id: string;
  grade: number;
  bank: 'specific';
  category: 'Ratio & Proportion' | 'Integers & Negatives' | 'Word Problem';
  level: 'Easy' | 'Medium' | 'Hard';
  question_en: string;
  question_ar: string;
  answer: number;
  methods: {
    vedic: LearnMethod;
    decompose: LearnMethod;
    visualize: LearnMethod;
  };
  meta: PracticeMeta;
}

export type PracticeProblem = LightPracticeProblem | FullPracticeProblem;

