export const getByCategory = (cat: string) =>
  grade6PracticeBank.filter(p => p.category === cat);

export const getByLevel = (level: 'Easy' | 'Medium' | 'Hard') =>
  grade6PracticeBank.filter(p => p.level === level);

export const getById = (id: string) =>
  grade6PracticeBank.find(p => p.id === id) ?? null;

export const getLightProblems = () =>
  grade6PracticeBank.filter((p): p is LightPracticeProblem => p.bank === 'common');

export const getFullProblems = () =>
  grade6PracticeBank.filter((p): p is FullPracticeProblem => p.bank === 'specific');
